// msgpack-mini — MessagePack binary codec (subset).
//
// Spec: https://github.com/msgpack/msgpack/blob/master/spec.md
// Implements: nil, bool, int (positive/negative fixint, uint8/16/32/64,
// int8/16/32/64), float64, fixstr/str8/str16/str32, fixarray/array16,
// fixmap/map16, bin8/16/32 (binary).
//
// Out of scope: float32 (we emit float64 for all numbers w/ fractional
// part), array32/map32 (>65535 elements), ext types, timestamps.
//
// Exercises Uint8Array slicing, DataView read/write at varying widths,
// bit-level mask matching for format-byte dispatch, recursion through
// composite types, character-set encoding via TextEncoder/TextDecoder.

const TEXT_ENC = new TextEncoder();
const TEXT_DEC = new TextDecoder();

// ── Encoder ────────────────────────────────────────────────────────
class Encoder {
    constructor() {
        this._chunks = [];
    }
    _push(chunk) { this._chunks.push(chunk); }
    bytes() {
        let total = 0;
        for (const c of this._chunks) total += c.length;
        const out = new Uint8Array(total);
        let off = 0;
        for (const c of this._chunks) { out.set(c, off); off += c.length; }
        return out;
    }
    encode(v) {
        if (v === null || v === undefined) {
            this._push(new Uint8Array([0xc0]));
        } else if (typeof v === "boolean") {
            this._push(new Uint8Array([v ? 0xc3 : 0xc2]));
        } else if (typeof v === "number") {
            if (Number.isInteger(v)) this._encodeInt(v);
            else this._encodeFloat(v);
        } else if (typeof v === "string") {
            this._encodeString(v);
        } else if (v instanceof Uint8Array) {
            this._encodeBinary(v);
        } else if (Array.isArray(v)) {
            this._encodeArray(v);
        } else if (typeof v === "object") {
            this._encodeMap(v);
        } else {
            throw new TypeError("msgpack-mini: unsupported type " + typeof v);
        }
    }
    _encodeInt(v) {
        if (v >= 0) {
            if (v <= 0x7f) { this._push(new Uint8Array([v])); return; }
            if (v <= 0xff) { this._push(new Uint8Array([0xcc, v])); return; }
            if (v <= 0xffff) {
                const b = new Uint8Array(3); b[0] = 0xcd;
                new DataView(b.buffer).setUint16(1, v); this._push(b); return;
            }
            if (v <= 0xffffffff) {
                const b = new Uint8Array(5); b[0] = 0xce;
                new DataView(b.buffer).setUint32(1, v); this._push(b); return;
            }
            const b = new Uint8Array(9); b[0] = 0xcf;
            new DataView(b.buffer).setBigUint64(1, BigInt(v));
            this._push(b); return;
        }
        if (v >= -32) { this._push(new Uint8Array([v & 0xff])); return; }
        if (v >= -128) { this._push(new Uint8Array([0xd0, v & 0xff])); return; }
        if (v >= -32768) {
            const b = new Uint8Array(3); b[0] = 0xd1;
            new DataView(b.buffer).setInt16(1, v); this._push(b); return;
        }
        if (v >= -2147483648) {
            const b = new Uint8Array(5); b[0] = 0xd2;
            new DataView(b.buffer).setInt32(1, v); this._push(b); return;
        }
        const b = new Uint8Array(9); b[0] = 0xd3;
        new DataView(b.buffer).setBigInt64(1, BigInt(v)); this._push(b);
    }
    _encodeFloat(v) {
        const b = new Uint8Array(9); b[0] = 0xcb;
        new DataView(b.buffer).setFloat64(1, v); this._push(b);
    }
    _encodeString(s) {
        const utf8 = TEXT_ENC.encode(s);
        const len = utf8.length;
        if (len <= 31) {
            const b = new Uint8Array(1 + len); b[0] = 0xa0 | len;
            b.set(utf8, 1); this._push(b); return;
        }
        if (len <= 0xff) {
            const b = new Uint8Array(2 + len); b[0] = 0xd9; b[1] = len;
            b.set(utf8, 2); this._push(b); return;
        }
        if (len <= 0xffff) {
            const b = new Uint8Array(3 + len); b[0] = 0xda;
            new DataView(b.buffer).setUint16(1, len);
            b.set(utf8, 3); this._push(b); return;
        }
        const b = new Uint8Array(5 + len); b[0] = 0xdb;
        new DataView(b.buffer).setUint32(1, len);
        b.set(utf8, 5); this._push(b);
    }
    _encodeBinary(u8) {
        const len = u8.length;
        if (len <= 0xff) {
            const b = new Uint8Array(2 + len); b[0] = 0xc4; b[1] = len;
            b.set(u8, 2); this._push(b); return;
        }
        if (len <= 0xffff) {
            const b = new Uint8Array(3 + len); b[0] = 0xc5;
            new DataView(b.buffer).setUint16(1, len);
            b.set(u8, 3); this._push(b); return;
        }
        const b = new Uint8Array(5 + len); b[0] = 0xc6;
        new DataView(b.buffer).setUint32(1, len);
        b.set(u8, 5); this._push(b);
    }
    _encodeArray(arr) {
        const len = arr.length;
        if (len <= 15) { this._push(new Uint8Array([0x90 | len])); }
        else if (len <= 0xffff) {
            const b = new Uint8Array(3); b[0] = 0xdc;
            new DataView(b.buffer).setUint16(1, len); this._push(b);
        } else throw new RangeError("msgpack-mini: array32 unsupported");
        for (const v of arr) this.encode(v);
    }
    _encodeMap(obj) {
        const keys = Object.keys(obj);
        const len = keys.length;
        if (len <= 15) { this._push(new Uint8Array([0x80 | len])); }
        else if (len <= 0xffff) {
            const b = new Uint8Array(3); b[0] = 0xde;
            new DataView(b.buffer).setUint16(1, len); this._push(b);
        } else throw new RangeError("msgpack-mini: map32 unsupported");
        for (const k of keys) { this.encode(k); this.encode(obj[k]); }
    }
}

export function encode(v) {
    const e = new Encoder();
    e.encode(v);
    return e.bytes();
}

// ── Decoder ────────────────────────────────────────────────────────
class Decoder {
    constructor(buf) {
        this._buf = buf;
        this._dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
        this._pos = 0;
    }
    decode() {
        const b = this._u8();
        // Fixed-prefix forms.
        if (b <= 0x7f) return b;                         // positive fixint
        if (b >= 0xe0) return b - 0x100;                 // negative fixint
        if ((b & 0xe0) === 0xa0) return this._str(b & 0x1f);
        if ((b & 0xf0) === 0x90) return this._array(b & 0x0f);
        if ((b & 0xf0) === 0x80) return this._map(b & 0x0f);
        switch (b) {
            case 0xc0: return null;
            case 0xc2: return false;
            case 0xc3: return true;
            case 0xc4: return this._bin(this._u8());
            case 0xc5: return this._bin(this._u16());
            case 0xc6: return this._bin(this._u32());
            case 0xca: { const v = this._dv.getFloat32(this._pos); this._pos += 4; return v; }
            case 0xcb: { const v = this._dv.getFloat64(this._pos); this._pos += 8; return v; }
            case 0xcc: return this._u8();
            case 0xcd: return this._u16();
            case 0xce: return this._u32();
            case 0xcf: { const v = this._dv.getBigUint64(this._pos); this._pos += 8;
                          return v <= BigInt(Number.MAX_SAFE_INTEGER) ? Number(v) : v; }
            case 0xd0: { const v = this._dv.getInt8(this._pos); this._pos += 1; return v; }
            case 0xd1: { const v = this._dv.getInt16(this._pos); this._pos += 2; return v; }
            case 0xd2: { const v = this._dv.getInt32(this._pos); this._pos += 4; return v; }
            case 0xd3: { const v = this._dv.getBigInt64(this._pos); this._pos += 8;
                          return (v >= BigInt(Number.MIN_SAFE_INTEGER) && v <= BigInt(Number.MAX_SAFE_INTEGER)) ? Number(v) : v; }
            case 0xd9: return this._str(this._u8());
            case 0xda: return this._str(this._u16());
            case 0xdb: return this._str(this._u32());
            case 0xdc: return this._array(this._u16());
            case 0xde: return this._map(this._u16());
            default: throw new Error("msgpack-mini: unknown prefix 0x" + b.toString(16));
        }
    }
    _u8()  { const v = this._dv.getUint8(this._pos); this._pos += 1; return v; }
    _u16() { const v = this._dv.getUint16(this._pos); this._pos += 2; return v; }
    _u32() { const v = this._dv.getUint32(this._pos); this._pos += 4; return v; }
    _str(len) {
        const slice = this._buf.subarray(this._pos, this._pos + len);
        this._pos += len;
        return TEXT_DEC.decode(slice);
    }
    _bin(len) {
        const slice = this._buf.slice(this._pos, this._pos + len);
        this._pos += len;
        return slice;
    }
    _array(len) {
        const out = new Array(len);
        for (let i = 0; i < len; i++) out[i] = this.decode();
        return out;
    }
    _map(len) {
        const out = {};
        for (let i = 0; i < len; i++) {
            const k = this.decode();
            out[k] = this.decode();
        }
        return out;
    }
}

export function decode(buf) {
    return new Decoder(buf).decode();
}

export default { encode, decode };
